async function main() {
  console.log('Updating categories for ' + DATA.length + ' products...');
  let updated = 0, skipped = 0;
  for (const { sku, categoryId } of DATA) {
    const r = await prisma.product.updateMany({ where: { sku }, data: { categoryId } });
    if (r.count > 0) updated++; else skipped++;
    if (updated % 500 === 0 && updated > 0) process.stdout.write(updated + '...');
  }
  console.log('Done - Updated: ' + updated + ' | Not found: ' + skipped);
  await prisma.$disconnect();
}
main().catch(async e => { console.error(e.message); await prisma.$disconnect(); process.exit(1); });
